#!/usr/bin/env python3
"""pre_merge_check.py — validates a feature branch is safe to merge into main.

Run this before opening a pull request or as a required CI merge gate step.
"""
import subprocess
import json
import sys

# Files that affect agent behaviour directly; conflicts here require extra care
CRITICAL_FILES = [
    "prompts/system_prompt.txt",
    "config/tool_definitions.json",
    "config/policy.yaml",
    "evals/golden_set.jsonl",
]


def get_changed_files(base_branch: str = "main") -> list[str]:
    """Return files changed on this branch relative to base_branch."""
    result = subprocess.run(
        ["git", "diff", "--name-only", f"{base_branch}...HEAD"],
        capture_output=True, text=True, check=True,
    )
    return [line for line in result.stdout.strip().split("\n") if line]


def check_critical_overlap(changed: list[str]) -> list[str]:
    """Return subset of changed files that are deemed critical."""
    return [f for f in changed if f in CRITICAL_FILES]


def detect_merge_conflicts(base_branch: str = "main") -> list[str]:
    """Dry-run a merge to surface conflicts; always abort before touching HEAD."""
    result = subprocess.run(
        ["git", "merge", "--no-commit", "--no-ff", base_branch],
        capture_output=True, text=True,
    )
    conflict_files: list[str] = []
    if result.returncode != 0:
        for line in (result.stderr + result.stdout).splitlines():
            if line.startswith("CONFLICT"):
                parts = line.split()
                if parts:
                    conflict_files.append(parts[-1])
    subprocess.run(["git", "merge", "--abort"], capture_output=True)
    return conflict_files


def run_eval_gate(min_score: float = 0.85) -> dict:
    """Run the agent eval suite and check whether it meets the threshold."""
    result = subprocess.run(
        ["python3", "evals/run_suite.py", "--output-json"],
        capture_output=True, text=True,
    )
    if result.returncode != 0:
        return {"passed": False, "score": 0.0, "error": result.stderr[:300]}
    try:
        data = json.loads(result.stdout)
    except json.JSONDecodeError as exc:
        return {"passed": False, "score": 0.0, "error": str(exc)}
    score = data.get("score", 0.0)
    return {"passed": score >= min_score, "score": score}


def main() -> int:
    base = sys.argv[1] if len(sys.argv) > 1 else "main"
    print(f"Checking branch against {base!r} ...")

    changed = get_changed_files(base)
    print(f"  Changed files: {len(changed)}")

    critical = check_critical_overlap(changed)
    if critical:
        print(f"  [WARN] Critical agent files modified: {critical}")
        print("         Re-run evals carefully after merge.")

    conflicts = detect_merge_conflicts(base)
    if conflicts:
        print(f"  [FAIL] Merge conflicts detected in: {conflicts}")
        return 1

    eval_result = run_eval_gate()
    if not eval_result["passed"]:
        err = eval_result.get("error", "")
        print(f"  [FAIL] Eval gate: score={eval_result['score']:.2%}  {err}")
        return 1

    print(f"  [PASS] Eval score: {eval_result['score']:.2%} — safe to merge.")
    return 0


if __name__ == "__main__":
    sys.exit(main())
